const raw = $json;

function parseMaybeJson(value) {
  if (value == null) return null;
  if (typeof value === 'object') return value;
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch {
      return null;
    }
  }
  return null;
}

let result = raw.result ?? raw.output ?? raw.data ?? raw;

if (Array.isArray(raw.content) && raw.content.length > 0) {
  const textPayload = raw.content.find((entry) => entry?.type === 'text')?.text ?? raw.content[0]?.text;
  const parsedText = parseMaybeJson(textPayload);
  if (parsedText && typeof parsedText === 'object') {
    result = parsedText;
  }
}

if (result?.content && Array.isArray(result.content) && result.content.length > 0) {
  const innerText = result.content.find((entry) => entry?.type === 'text')?.text ?? result.content[0]?.text;
  const parsedInner = parseMaybeJson(innerText);
  if (parsedInner && typeof parsedInner === 'object') {
    result = parsedInner;
  }
}

const archivos = Number(result?.archivos_encontrados ?? 0);

return [{
  json: {
    archivos_encontrados: Number.isFinite(archivos) ? archivos : 0,
    stores_escaneados: result?.stores_escaneados ?? [],
    archivos: Array.isArray(result?.archivos) ? result.archivos : [],
    raw
  }
}];

