const raw = $json;

function parseMaybeJson(value) {
  if (value == null) return null;
  if (typeof value === 'object') return value;
  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch {
      return null;
    }
  }
  return null;
}

let result = raw.result ?? raw.output ?? raw.data ?? raw;

if (Array.isArray(raw.content) && raw.content.length > 0) {
  const textPayload = raw.content.find((entry) => entry?.type === 'text')?.text ?? raw.content[0]?.text;
  const parsedText = parseMaybeJson(textPayload);
  if (parsedText && typeof parsedText === 'object') {
    result = parsedText;
  }
}

if (result?.content && Array.isArray(result.content) && result.content.length > 0) {
  const innerText = result.content.find((entry) => entry?.type === 'text')?.text ?? result.content[0]?.text;
  const parsedInner = parseMaybeJson(innerText);
  if (parsedInner && typeof parsedInner === 'object') {
    result = parsedInner;
  }
}

const jobs = Array.isArray(result?.jobs) ? result.jobs : [];

let batchIds = [];
try {
  const fromGuardarBatch = $('Guardar Batch').first().json;
  if (Array.isArray(fromGuardarBatch?.job_ids)) {
    batchIds = fromGuardarBatch.job_ids;
  }
} catch (e) {
  batchIds = [];
}

const batchJobs = jobs.filter((j) => batchIds.includes(j.job_id));

const summary = {
  total: batchJobs.length,
  queued: batchJobs.filter((j) => j.status === 'queued').length,
  running: batchJobs.filter((j) => j.status === 'running').length,
  uploading: batchJobs.filter((j) => j.status === 'uploading').length,
  completed: batchJobs.filter((j) => j.status === 'completed').length,
  failed: batchJobs.filter((j) => j.status === 'failed').length,
  skipped_duplicate: batchJobs.filter((j) => j.status === 'skipped_duplicate').length
};

const pendientes = summary.queued + summary.running + summary.uploading;
const hasPending = pendientes > 0;

return [{
  json: {
    batch_job_ids: batchIds,
    batch_jobs: batchJobs,
    summary,
    pendientes,
    hasPending
  }
}];

const s = $json.summary || {};
const texto = `Ingesta RAG OCRL Mendoza finalizada. Total: ${s.total ?? 0}, completed: ${s.completed ?? 0}, skipped_duplicate: ${s.skipped_duplicate ?? 0}, failed: ${s.failed ?? 0}.`;
return [{ json: { store: 'odoo-mendoza', estado: 'finalizado', summary: s, mensaje: texto } }];
